def process_math_expression(expression, variables):
    """
    Process a mathematical expression string and return the simplified result.

    Args:
        expression (str): A mathematical expression string.
        variables (dict): A dictionary of variable names and their values.

    Returns:
        str: The simplified expression as a string.

    Raises:
        ValueError: If the expression is invalid or cannot be processed.
    """
    # Define supported operators
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    def eval_node(node):
        # Handle numbers (Python 3.8+ uses ast.Constant for numbers)
        if isinstance(node, ast.Constant):
            if not isinstance(node.value, (int, float)):
                raise ValueError(f"Unsupported constant type: {type(node.value)}")
            return node.value
        # Backward compatibility for Python < 3.8
        elif isinstance(node, ast.Num):
            return node.n
        # Handle variables
        elif isinstance(node, ast.Name):
            if node.id in variables:
                val = variables[node.id]
                if not isinstance(val, (int, float)):
                    raise ValueError(f"Variable {node.id} must be a numeric value")
                return val
            raise ValueError(f"Undefined variable: {node.id}")
        # Handle binary operations (+, -, *, /)
        elif isinstance(node, ast.BinOp):
            left = eval_node(node.left)
            right = eval_node(node.right)
            op_type = type(node.op)
            if op_type not in operators:
                raise ValueError(f"Unsupported operator: {op_type.__name__}")
            if op_type == ast.Div and right == 0:
                raise ValueError("Division by zero")
            return operators[op_type](left, right)
        # Handle unary operations (-x, +x)
        elif isinstance(node, ast.UnaryOp):
            operand = eval_node(node.operand)
            op_type = type(node.op)
            if op_type not in operators:
                raise ValueError(f"Unsupported unary operator: {op_type.__name__}")
            return operators[op_type](operand)
        else:
            raise ValueError(f"Unsupported expression element: {type(node).__name__}")

    try:
        # Parse the expression into an AST
        # mode='eval' ensures the input is a single expression
        tree = ast.parse(expression.strip(), mode='eval')
        result = eval_node(tree.body)
        # Return as string, formatting floats to remove trailing .0 if they are integers
        if isinstance(result, float) and result.is_integer():
            return str(int(result))
        return str(result)
    except (SyntaxError, TypeError, KeyError) as e:
        raise ValueError(f"Invalid expression: {e}")
    except Exception as e:
        if isinstance(e, ValueError):
            raise e
        raise ValueError(f"An error occurred while processing the expression: {e}")

