def view_user_profile(current_user_id: int, target_user_id: int):
    """
    View user profile based on authorization checks.
    :param current_user_id: int the 'user_id' of the actor requesting the profile
    :param target_user_id: int the 'user_id' of the profile being viewed
    :return: The profile data if authorized to view or 'Unauthorized'
    """
    # Validate that the current user exists in the system
    if current_user_id not in USERS:
        return "Unauthorized"

    # Validate that the target profile exists
    if target_user_id not in USER_PROFILES:
        return "Unauthorized"

    # Authorization Logic:
    # 1. User is viewing their own profile
    # 2. User has the 'admin' role
    is_owner = (current_user_id == target_user_id)
    is_admin = (USERS[current_user_id].get("role") == "admin")

    if is_owner or is_admin:
        return USER_PROFILES[target_user_id]

    return "Unauthorized"

