    user = USERS.get(current_user_id)
    content = CONTENT.get(content_id)

    # If user or content does not exist, deny access
    if not user or not content:
        return 'Access Denied'

    # Admins have unrestricted access to all content
    if user.get('role') == 'admin':
        return content.get('title', 'Access Denied')

    # Define subscription hierarchy
    # Premium users can access both basic and premium content
    # Basic users can only access basic content
    user_level = user.get('subscription_level')
    required_level = content.get('required_level')

    if user_level == 'premium':
        return content.get('title', 'Access Denied')

    if user_level == 'basic' and required_level == 'basic':
        return content.get('title', 'Access Denied')

    return 'Access Denied'

